1642	        LOG_DBG("Using specialized template: Ministral/Magistral Large 3\n");
1643	        return common_chat_params_init_ministral_3(tmpl, params);
1644	    }
1645	
1646	    // GPT-OSS - has unique channel-based structure that needs dedicated handler
1647	    if (src.find("<|channel|>") != std::string::npos) {
1648	        LOG_DBG("Using specialized template: GPT-OSS\n");
1649	        return common_chat_params_init_gpt_oss(tmpl, params);
1650	    }
1651	
1652	    // Functionary v3.2 - uses recipient-based format with >>>recipient\n{content}
1653	    // Detection: template has ">>>all" for content and ">>>" prefix for tool calls
1654	    if (src.find(">>>all") != std::string::npos && src.find(">>>${recipient}") != std::string::npos) {
1655	        LOG_DBG("Using specialized template: Functionary v3.2\n");
1656	        return common_chat_params_init_functionary_v3_2(tmpl, params);
1657	    }
1658	
1659	    // Kimi K2 Thinking - uses unique tool call ID format: functions.<name>:<index>
1660	    // Detection: template has "<|tool_calls_section_begin|>" and "functions." prefix in tool call IDs
1661	    if (src.find("<|tool_calls_section_begin|>") != std::string::npos &&
1662	        src.find("<|tool_call_begin|>") != std::string::npos) {
1663	        LOG_DBG("Using specialized template: Kimi K2 Thinking\n");
